mapper.select:
SELECT id, provider_key_id, window_type, quota_limit, quota_used,
       window_start_at, reset_at, status, updated_at
FROM provider_key_quota_window
WHERE provider_key_id = #{providerKeyId}
  AND window_type = #{windowType}

mapper.update:
UPDATE provider_key_quota_window
SET quota_used = quota_used + #{amount},
    updated_at = CURRENT_TIMESTAMP
WHERE provider_key_id = #{providerKeyId}
  AND window_type = #{windowType}
